import AddCommentIcon from '@mui/icons-material/AddComment';
import { Button, Card, CardContent, Typography } from '@mui/material';
import Avatar from '@mui/material/Avatar';
import ButtonGroup from '@mui/material/ButtonGroup';
import { purple } from '@mui/material/colors';
import Divider from '@mui/material/Divider';
import List from '@mui/material/List';
import ListItem from '@mui/material/ListItem';
import ListItemAvatar from '@mui/material/ListItemAvatar';
import ListItemText from '@mui/material/ListItemText';
import dateFormat from 'dateformat';
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router';
import { createAPIEndpoint, ENDPOINTS } from '../api';
import '../App.css';
import useForm from '../hooks/useForm';
import useStateContext from '../hooks/useStateContext';
import Center from './Center';
import FavoriteBorderIcon from '@mui/icons-material/FavoriteBorder';
var ids = 0;
var uid = 0;

const getFreshModel = () => ({




})




export default function HomePage() {


  const [sata, setSata] = useState([])
  const [qnIndex, setQnIndex] = useState(1)
  const { context, setContext } = useStateContext()
  const { resetContext } = useStateContext()
  const navigate = useNavigate()
  const [tdid, setidid] = useState()

  useEffect(() => {
    setContext({
      timeTaken: 0,
      selectedOptions: []
    })
    createAPIEndpoint(ENDPOINTS.alltweets)
      .fetch()
      .then(res => {
        setSata(res.data)


      })
      .catch(err => { console.log(err); })



  }, [])




  const Liketw = e => {

    createAPIEndpoint(ENDPOINTS.postcomments)
      .putlk(uid, qnIndex)
      .then(
        console.log(values)

      )
      .catch(err => console.log(err))
  }



  const {
    id = 1,
    values,
    setValues,
    errors,
    setErrors,
    handleInputChange
  } = useForm(getFreshModel);


  const logout = () => {
    resetContext()
    navigate("/")
  }

  const handleClick = value => () => navigate("/Addcomment", { state: { id: 1, name: value } })

  const handleClick1 = value => () => setQnIndex(value)

  uid = context.userId

  console.log(sata)

  return (
    sata.length !== 0
      ?
      <Center>


        <Card sx={{ width: 800 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <Typography variant="h3" sx={{ my: 3 }}>
              Ash Tweet
            </Typography>




            <Typography component="h1" variant="h5">
              {'Hello ' + context.userName + '! Whats on your Mind ?'}
            </Typography>
            <br></br>

            <ButtonGroup variant="contained" aria-label="outlined primary button group">
              <Button onClick={() => {
                window.location.href = "/postNewTweet"
              }}>Post New Tweet</Button>

              <Button onClick={() => {
                window.location.href = "/homepage"
              }}
              >Home Feed</Button>

              <Button onClick={() => {
                window.location.href = "/ViewAllUsers"
              }}

              >View All Users</Button>

              <Button onClick={() => {
                window.location.href = "/ViewMyTweets"
              }}
              >View My Tweets</Button>

              <Button onClick={() => {
                window.location.href = "/ForgetPass"
              }}
              >Password Reset</Button>


              <Button onClick={() => { logout() }
              }
              >LogOut</Button>




            </ButtonGroup>




            <ul >
              {sata.slice(0).reverse().map(d => (<li key={d.tweetId}>





                <Divider variant="middle" />




                <List sx={{ width: '100%', maxWidth: '90%', bgcolor: 'background.paper' }}>
                  <ListItem alignItems="flex-start">
                    <ListItemAvatar>
                      <Avatar sx={{ bgcolor: purple[500] }}>{d.userName[0]}</Avatar>
                    </ListItemAvatar>
                    <ListItemText

                      secondary={
                        <React.Fragment>
                          <Typography
                            sx={{ display: 'inline' }}
                            component="span"
                            variant="subtitle1"
                            color="text.primary"
                          >
                            {d.tweetContent}
                          </Typography>

                          <br></br>
                          <Typography
                            sx={{ display: 'inline' }}
                            component="span"
                            variant="h6"
                            color="text.primary"
                          >
                            {d.userName}
                          </Typography>
                          <br></br>
                          {dateFormat(d.id.creationTime, "dddd, mmmm dS, yyyy,HH:mm:ss")}


                          <form noValidate autoComplete="off" await onSubmit={Liketw}>

                            <Button

                              size='Large'
                              id={d.tweetId}
                              variant="text"
                              onClick={
                                handleClick(d.tweetId)
                              }
                              endIcon={<AddCommentIcon />}
                            >

                            </Button>



                            <Button
                              type='submit'
                              size='Large'
                              id={d.tweetId}
                              variant="text"
                              onClick={
                                handleClick1(d.tweetId)
                              }
                              endIcon={<FavoriteBorderIcon />}
                            >

                            </Button>
                          </form>

                          <br></br>
                          <Typography
                            sx={{ display: 'inline' }}
                            component="span"
                            variant="body1"
                            color="text.primary"
                          >


                            {d.commentorContent !== null ? " Reply:" + d.commentorContent : null}

                            {d.commentorUserName !== null ? " by " + d.commentorUserName : null}


                          </Typography>
                              <br></br>
                          Total Likes:{ids = new Set(d.tweetLike).size}
                        </React.Fragment>
                      }
                    />
                  </ListItem>
                </List>



              </li>))}

            </ul>





          </CardContent>
        </Card>
      </Center>
      : <Center>


        <Card sx={{ width: 800 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <Typography variant="h3" sx={{ my: 3 }}>
              Ash Tweet
            </Typography>


            {() => getFreshModel(context.userName)}

            <Typography component="h1" variant="h5">
              {'Hello ' + context.userName + '! No Tweets For You'}
            </Typography>

            <ButtonGroup variant="contained" aria-label="outlined primary button group">
              <Button onClick={() => {
                window.location.href = "/postNewTweet"
              }}>Post New Tweet</Button>

              <Button onClick={() => {
                window.location.href = "/homepage"
              }}
              >Home Feed</Button>

              <Button onClick={() => {
                window.location.href = "/ViewAllUsers"
              }}

              >View All Users</Button>

              <Button onClick={() => {
                window.location.href = "/ViewMyTweets"
              }}
              >View My Tweets</Button>

              <Button onClick={() => {
                window.location.href = "/ForgetPass"
              }}
              >Password Reset</Button>


              <Button onClick={() => {
                window.location.href = "/"
              }}
              >LogOut</Button>




            </ButtonGroup>











          </CardContent>
        </Card>
      </Center>
  )
}

