import React from 'react'
import { Button, Card, CardContent, TextField, Typography } from '@mui/material'
import { Box } from '@mui/system'
import Center from './Center'
import useForm from '../hooks/useForm'
import { createAPIEndpoint, ENDPOINTS } from '../api'
import { useNavigate } from 'react-router'
import { Link } from "react-router-dom";

import FormControl from '@mui/material/FormControl';
import Radio from '@mui/material/Radio';
import RadioGroup from '@mui/material/RadioGroup';
import FormControlLabel from '@mui/material/FormControlLabel';
import FormLabel from '@mui/material/FormLabel';




const getFreshModel = () => ({
  userName: '',
  mailId: '',
  password: '',
  gender: '',
  profilePictureBase64: '',
  userBio: ''

})

function Copyright(props) {
  return (
    <Typography variant="body2" color="text.secondary" align="center" {...props}>
      {'Copyright © '}
      AshTweet
      {new Date().getFullYear()}
      {'.'}
    </Typography>
  );
}



export default function Register() {
  const navigate = useNavigate()



  const register = e => {
    e.preventDefault();
    if (validate())
    createAPIEndpoint(ENDPOINTS.register)
    .post(values)
    .then(res =>{

      console.log(res)
      navigate("/")

    } )
    .catch(err => console.log(err))
  }

  const {
    values,
    setValues,
    errors,
    setErrors,
    handleInputChange
  } = useForm(getFreshModel);


  const validate = () => {
    let temp = {}
    temp.mailId = (/\S+@\S+\.\S+/).test(values.mailId) ? "" : "Email is not valid."
    temp.password = values.password !== "" ? "" : "Password Cannot Be Empty."
    temp.userName = values.userName !== "" ? "" : "This Feild Cannot Be Empty."
    setErrors(temp)
    return Object.values(temp).every(x => x === "")
  }


  return (

    <Center>
      <Card sx={{ width: 400 }}>
        <CardContent sx={{ textAlign: 'center' }}>
          <Typography variant="h3" sx={{ my: 3 }}>
            Ash Tweet
          </Typography>
          <Box sx={{
            '& .MuiTextField-root': {
              m: 1,
              width: '90%'
            }
          }}>
            <form noValidate autoComplete="off" onSubmit={register}>

              <Typography component="h1" variant="h5">
                Sign up
              </Typography>
              <TextField
                label="Enter Your Name"
                name="userName"
                value={values.userName}
                onChange={handleInputChange}
                variant="outlined"
                {...(errors.userName && { error: true, helperText: errors.userName })} />
              <TextField
                label="Email"
                name="mailId"
                value={values.mailId}
                onChange={handleInputChange}
                variant="outlined"
                {...(errors.mailId && { error: true, helperText: errors.mailId })} />
              <TextField
                label="Password"
                name="password"
                type="password"
                value={values.password}
                onChange={handleInputChange}
                variant="outlined"
                {...(errors.password && { error: true, helperText: errors.password })} />
              <TextField
                label="Enter Your Bio"
                name="userBio"
                value={values.userBio}
                onChange={handleInputChange}
                variant="outlined"
                {...(errors.userName && { error: true, helperText: errors.userName })} />

              <FormControl>
                <FormLabel id="gender-group">Gender</FormLabel>
                <RadioGroup
                  row
                  aria-labelledby="-buttons-group"
                  name="gender"
                  value={values.gender}
                  onChange={handleInputChange}
                >
                  <FormControlLabel value="female" control={<Radio />} label="Female" />
                  <FormControlLabel value="male" control={<Radio />} label="Male" />
                </RadioGroup>
              </FormControl>

              <Button
                type="submit"
                variant="contained"
                size="large"
                sx={{ width: '90%' }}>Sign-Up</Button>





              <Link to="/" variant="body2">Already have an account? Sign in</Link>


            </form>

            <Copyright sx={{ mt: 5 }} />

          </Box>
        </CardContent>
      </Card>

    </Center>
  )
}
