import { Button, Card, CardContent, Typography } from '@mui/material';
import Avatar from '@mui/material/Avatar';
import ButtonGroup from '@mui/material/ButtonGroup';
import { purple } from '@mui/material/colors';
import Divider from '@mui/material/Divider';
import ListItem from '@mui/material/ListItem';
import ListItemAvatar from '@mui/material/ListItemAvatar';
import ListItemText from '@mui/material/ListItemText';
import React, { useEffect, useState } from 'react';
import { createAPIEndpoint, ENDPOINTS } from '../api';
import '../App.css';
import useStateContext from '../hooks/useStateContext';
import Center from './Center';


const getFreshModel = () => ({

  commentorContent: '',


})






export default function ViewAllUsers() {

  const [jata, setSata] = useState([])

  const { context, setContext } = useStateContext()

  useEffect(() => {
    setContext({
      timeTaken: 0,
      selectedOptions: []
    })
    createAPIEndpoint(ENDPOINTS.alluser)
      .fetch()
      .then(res => {
        setSata(res.data)


      })
      .catch(err => { console.log(err); })



  }, [])













  console.log(jata)





  return (


    jata.length !== 0
      ?
      <Center>


        <Card sx={{ width: 800 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <Typography variant="h3" sx={{ my: 3 }}>
              Ash Tweet
            </Typography>


            {() => getFreshModel(context.userName)}

            <Typography component="h1" variant="h5">
              {'Hello ' + context.userName + '! Here are our Users'}
            </Typography>

            <ButtonGroup variant="contained" aria-label="outlined primary button group">
            <Button onClick={() => {
              window.location.href = "/postNewTweet"
            }}>Post New Tweet</Button>

            <Button onClick={() => {
              window.location.href = "/homepage"
            }}
            >Home Feed</Button>

            <Button onClick={() => {
              window.location.href = "/ViewAllUsers"
            }}

            >View All Users</Button>

            <Button onClick={() => {
              window.location.href = "/ViewMyTweets"
            }}
            >View My Tweets</Button>

            <Button onClick={() => {
              window.location.href = "/ForgetPass"
            }}
            >Password Reset</Button>







          </ButtonGroup>




            <ul >
              {jata.map(d => (<li key={d.userId}>





                <Divider variant="inset" />



                <ListItem alignItems="flex-start">
                  <ListItemAvatar>
                  <Avatar sx={{ bgcolor:purple[500] }}>{d.userName[0]}</Avatar>
                  </ListItemAvatar>

                  <Typography
                    sx={{ display: 'inline' }}
                    component="h6"
                    variant="body3"
                    color="text.primary"

                  >


                  </Typography>




                  <ListItemText


                    secondary={

                        <Typography
                          sx={{ display: 'inline' }}
                          component="span"
                          variant="body1"
                          color="text.primary"
                        >
                           {d.userId}{'     -     '}{d.userName}
                        </Typography>




                    }
                  />
                </ListItem>






              </li>))}

            </ul>





          </CardContent>
        </Card>
      </Center>
      : null







  )
}
