import React from 'react'
import { Button, Card, CardContent, TextField, Typography } from '@mui/material'
import { Box } from '@mui/system'
import Center from './Center'
import useForm from '../hooks/useForm'
import { createAPIEndpoint, ENDPOINTS } from '../api'
import ButtonGroup from '@mui/material/ButtonGroup';
import { useNavigate } from 'react-router'
import useStateContext from '../hooks/useStateContext'
import Context from '@mui/base/TabsUnstyled/TabsContext'

let vsed = 0;
let vsnm = '';

const getFreshModel = () => ({

  tweetContent: '',
  userName: vsnm,
  userId: vsed,
  TweetLike: [ ]


})



function Copyright(props) {
  return (
    <Typography variant="body2" color="text.secondary" align="center" {...props}>
      {'Copyright © '}
      AshTweet
      {new Date().getFullYear()}
      {'.'}
    </Typography>
  );
}






export default function PostNewTweet() {

  const navigate = useNavigate()
  const { context, setContext } = useStateContext()

  vsed = context.userId
  vsnm = context.userName






  const postweet = e => {
    e.preventDefault();
    createAPIEndpoint(ENDPOINTS.posttweets)
      .post(values)
      .then(res => {

        console.log(values)
        navigate("/HomePage")


      })
      .catch(err => console.log(err))
  }

  const {
    values,
    setValues,
    errors,
    setErrors,
    handleInputChange
  } = useForm(getFreshModel);





  return (
    <Center>
      <Card sx={{ width: '100%' }}>
        <CardContent sx={{ textAlign: 'center' }}>
          <Typography variant="h3" sx={{ my: 3 }}>
            Ash Tweet
          </Typography>

          <Box sx={{
            '& .MuiTextField-root': {
              m: 1,
              width: '90%'
            }
          }}>


            <ButtonGroup variant="contained" aria-label="outlined primary button group">
              <Button onClick={() => {
                window.location.href = "/postNewTweet"
              }}>Post New Tweet</Button>

              <Button onClick={() => {
                window.location.href = "/homepage"
              }}
              >Home Feed</Button>

              <Button onClick={() => {
                window.location.href = "/ViewAllUsers"
              }}

              >View All Users</Button>

              <Button onClick={() => {
                window.location.href = "/ViewMyTweets"
              }}
              >View My Tweets</Button>

              <Button onClick={() => {
                window.location.href = "/ForgetPass"
              }}
              >Password Reset</Button>


            </ButtonGroup>

            <form noValidate autoComplete="off" onSubmit={postweet}>

              <Typography component="h1" variant="h5"

              >
                Post New Tweet
              </Typography>

              <TextField
                label="Enter Your Thoughts"
                name="tweetContent"
                value={values.tweetContent}
                onChange={handleInputChange}
                variant="outlined"
                multiline
                rows={4}
              />





              <Button
                type="submit"
                variant="contained"
                size="large"

                sx={{ width: '90%' }}>Post Tweet</Button>







            </form>

            <Copyright sx={{ mt: 5 }} />

          </Box>
        </CardContent>
      </Card>

    </Center>







  )
}
