import { Button, Card, CardContent, TextField, Typography } from '@mui/material';
import Alert from '@mui/material/Alert';
import ButtonGroup from '@mui/material/ButtonGroup';
import { Box } from '@mui/system';
import React from 'react';
import { useNavigate } from 'react-router';
import { useLocation } from "react-router-dom";
import { createAPIEndpoint, ENDPOINTS } from '../api';
import useForm from '../hooks/useForm';
import useStateContext from '../hooks/useStateContext';
import Center from './Center';
 var twtid=3
 var namez=''

 const getFreshModel = () => ({

    CommentorContent: '',


    })



  function Copyright(props) {
    return (
      <Typography variant="body2" color="text.secondary" align="center" {...props}>
        {'Copyright © '}
        AshTweet
        {new Date().getFullYear()}
        {'.'}
      </Typography>
    );
  }



export default function Addcomment() {
    const location = useLocation();
    const navigate = useNavigate()
    const { context, setContext } = useStateContext()

    twtid=location.state.name
    namez=context.userName

    const postcomments = e => {
        e.preventDefault();
        createAPIEndpoint(ENDPOINTS.postcomments)
          .putco(twtid,values.CommentorContent,namez)
          .then(
              console.log(values),
              <Alert severity="success">Sucessfully Commented</Alert>,
              navigate("/HomePage")

          )
          .catch(err => console.log(err))
      }


    const {
        values,
        setValues,
        errors,
        setErrors,
        handleInputChange
      } = useForm(getFreshModel);




  return (
<Center>
          <Card sx={{ width: '90%' }}>
            <CardContent sx={{ textAlign: 'center' }}>
              <Typography variant="h3" sx={{ my: 3 }}>
                Ash Tweet
              </Typography>

              <Box sx={{
                '& .MuiTextField-root': {
                  m: 1,
                  width: '90%'
                }
              }}>


    <ButtonGroup variant="contained" aria-label="outlined primary button group">
                <Button onClick={() => {
                  window.location.href = "/postNewTweet"
                }}>Post New Tweet</Button>

                <Button onClick={() => {
                  window.location.href = "/homepage"
                }}
                >Home Feed</Button>

                <Button onClick={() => {
                  window.location.href = "/ViewAllUsers"
                }}

                >View All Users</Button>

                <Button onClick={() => {
                  window.location.href = "/ViewMyTweets"
                }}
                >View My Tweets</Button>

                <Button onClick={() => {
                  window.location.href = "/ForgetPass"
                }}
                >Password Reset</Button>







              </ButtonGroup>

                <form noValidate autoComplete="off" onSubmit={postcomments}>

                  <Typography component="h1" variant="h5"

                  >
                  Enter Your Comment
                  </Typography>

                  <TextField
                    label="Enter Your Comment"
                    name="CommentorContent"
                    value={values.CommentorContent}
                    onChange={handleInputChange}
                    variant="outlined"
                    multiline
                    rows={4}
                     />





                  <Button
                    type="submit"
                    variant="contained"
                    size="large"

                    sx={{ width: '90%' }}>Comment UP</Button>







                </form>

                <Copyright sx={{ mt: 5 }} />

              </Box>
            </CardContent>
          </Card>

        </Center>




  )
}
