import React from 'react'
import { Button, Card, CardContent, TextField, Typography } from '@mui/material'
import { Box } from '@mui/system'
import Center from './Center'
import useForm from '../hooks/useForm'
import { createAPIEndpoint, ENDPOINTS } from '../api'
import { useNavigate } from 'react-router'
import { Link } from "react-router-dom";
import { createTheme } from '@mui/material/styles';
import useStateContext from '../hooks/useStateContext'



const getFreshModel = () => ({
    mailId: '',
    password: ''
})

function Copyright(props) {
    return (
      <Typography variant="body2" color="text.secondary" align="center" {...props}>
        {'Copyright © '}
          AshTweet
        {new Date().getFullYear()}
        {'.'}
      </Typography>
    );
  }






export default function Login() {

  const { context, setContext } = useStateContext();
  const navigate = useNavigate()

    const login = e => {
        e.preventDefault();
        if (validate())
            createAPIEndpoint(ENDPOINTS.login)
                .post(values)
                .then(res => {

                  if(res.data!=='UnAuthorized')
                  {
                    setContext({ gender: res.data.results.gender
                      , mailId: res.data.results.mailId
                      , password: res.data.results.password
                      , profilePictureBase64: res.data.results.profilePictureBase64
                      , userBio: res.data.results.userBio
                      , userId: res.data.results.userId
                      , userName: res.data.results.userName
                      , token: res.data.results.token
                    })

                    navigate("/HomePage")

                  }

                  console.log(res)})
                .catch(err => console.log(err))
    }

    const {
        values,
        errors,
        setErrors,
        handleInputChange
    } = useForm(getFreshModel);




    const validate = () => {
        let temp = {}
        temp.mailId = (/\S+@\S+\.\S+/).test(values.mailId) ? "" : "Email is not valid."
        temp.name = values.password !== "" ? "" : "Password Cannot Be Empty."
        setErrors(temp)
        return Object.values(temp).every(x => x === "")
    }



  return (
    <Center>


    <Card sx={{ width: 400 }}>
        <CardContent sx={{ textAlign: 'center' }}>
            <Typography variant="h3" sx={{ my: 3 }}>
                Ash Tweet
            </Typography>
                      <Box sx={{
                '& .MuiTextField-root': {
                    m: 1,
                    width: '90%'
                }
            }}>
                <form noValidate autoComplete="off" onSubmit={login}>

          <Typography component="h1" variant="h5">
            Sign In
          </Typography>

                    <TextField
                        label="Email"
                        name="mailId"
                        value={values.mailId}
                        onChange={handleInputChange}
                        variant="outlined"
                        {...(errors.mailId && { error: true, helperText: errors.mailId })} />
                    <TextField
                        label="Password"
                        name="password"
                        type="password"
                        value={values.password}
                        onChange={handleInputChange}
                        variant="outlined"
                        {...(errors.password && { error: true, helperText: errors.password })}  />
                    <Button
                        type="submit"
                        variant="contained"
                        size="large"

                        sx={{ width: '90%' }}>Log-In</Button>

<Link to="/Register">Don't Have one Acoount? SignUp Here</Link>
<br></br>
<Link to="/ForgetPassOne">Forgot your Password ?</Link>

                </form>



                <Copyright sx={{ mt: 5 }} />

            </Box>
        </CardContent>
    </Card>
</Center>
  )
}
