import React from 'react'
import { Button, Card, CardContent, TextField, Typography } from '@mui/material'
import { Box } from '@mui/system'
import Center from './Center'
import useForm from '../hooks/useForm'
import { createAPIEndpoint, ENDPOINTS } from '../api'
import { useNavigate } from 'react-router'


const getFreshModel = () => ({
    mailId: '',
    userName: ''

})

function Copyright(props) {
    return (
      <Typography variant="body2" color="text.secondary" align="center" {...props}>
        {'Copyright © '}
          AshTweet
        {new Date().getFullYear()}
        {'.'}
      </Typography>
    );
  }









export default function ForgetPassOne() {


    const navigate = useNavigate()

      const jorgetPassOne = e => {
          e.preventDefault();
          if (validate())
              createAPIEndpoint(ENDPOINTS.forgetone)
                  .post(values)
                  .then(res => {

                    if(res.data!=='UnAuthorized')
                    {

                      navigate("/ForgetPass")
                      console.log(res)

                    }

                    console.log(res)})
                  .catch(err => console.log(err))
      }

      const {
          values,
          errors,
          setErrors,
          handleInputChange
      } = useForm(getFreshModel);




      const validate = () => {
          let temp = {}
          temp.mailId = (/\S+@\S+\.\S+/).test(values.mailId) ? "" : "Email is not valid."
          temp.userName = values.userName !== "" ? "" : "userName Cannot Be Empty."
          setErrors(temp)
          return Object.values(temp).every(x => x === "")
      }




  return (
    <Center>


    <Card sx={{ width: 400 }}>
        <CardContent sx={{ textAlign: 'center' }}>
            <Typography variant="h3" sx={{ my: 3 }}>
                Ash Tweet
            </Typography>
                      <Box sx={{
                '& .MuiTextField-root': {
                    m: 1,
                    width: '90%'
                }
            }}>
                <form noValidate autoComplete="off" onSubmit={jorgetPassOne}>

          <Typography component="h1" variant="h5">
            Resetting Password
          </Typography>

                    <TextField
                        label="Email"
                        name="mailId"
                        value={values.mailId}
                        onChange={handleInputChange}
                        variant="outlined"
                        {...(errors.mailId && { error: true, helperText: errors.mailId })} />
                    <TextField
                        label="UserName"
                        name="userName"
                        value={values.userName}
                        onChange={handleInputChange}
                        variant="outlined"
                        {...(errors.userName && { error: true, helperText: errors.userName })}  />
                    <Button
                        type="submit"
                        variant="contained"
                        size="large"

                        sx={{ width: '90%' }}>Reset</Button>



                </form>



                <Copyright sx={{ mt: 5 }} />

            </Box>
        </CardContent>
    </Card>
</Center>
  )
}
