import axios from 'axios'

export const BASE_URL = 'https://localhost:7087/';

export const ENDPOINTS = {
    login: 'Login',
    register:'Register/NewUser',
    alltweets : 'Tweet/AllTweet',
    posttweets : 'Tweet/NewTweet',
    postcomments:'Tweet',
    forgetone:'Login/OneForgetPass',
    alluser:'Register/AllUser'
}

export const createAPIEndpoint = endpoint => {

    let url = BASE_URL + 'api/' + endpoint + '/';
    return {
        fetch: () => axios.get(url),

        fetchById: id => axios.get(url+'MyTweet?UserId='+ id),
        fetchByIds: id => axios.put(url+'AddComment?tweetId='+ id),
        post: newRecord => axios.post(url, newRecord),
        putno: newRecord => axios.put(url, newRecord),
        put: (id, updatedRecord) => axios.put(url+'AddComment?tweetId='+ id, updatedRecord),
        putlk: (id, updatedRecord) => axios.put(url+'UpdateLike?userId='+ id + '&tweetid=' + updatedRecord),
        puttw: (id, updatedRecord) => axios.put(url+'UpdateTweet?tweetId='+ id +'&TweetContent='+updatedRecord),
        putco: (id, updatedRecord,updatedRecord1) => axios.put(url+'AddComment?tweetId='+ id +'&CommentorContent='+updatedRecord+'&CommentorUserName='+updatedRecord1),
        delete: id => axios.delete(url +'DeleteMyTweet?tweetId='+ id),
    }
}