import DeleteIcon from '@mui/icons-material/Delete';
import { Button, Card, CardContent, Typography } from '@mui/material';
import Avatar from '@mui/material/Avatar';
import ButtonGroup from '@mui/material/ButtonGroup';
import { purple } from '@mui/material/colors';
import Divider from '@mui/material/Divider';
import ListItem from '@mui/material/ListItem';
import ListItemAvatar from '@mui/material/ListItemAvatar';
import ListItemText from '@mui/material/ListItemText';
import dateFormat from 'dateformat';
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router';
import { createAPIEndpoint, ENDPOINTS } from '../api';
import '../App.css';
import useForm from '../hooks/useForm';
import useStateContext from '../hooks/useStateContext';
import Center from './Center';















export default function ViewMyTweets() {

  const getFreshModel = () => ({
    id: {
      "timestamp": 0
    },
    tweetId: 0,
    userId: 0,
    userName: qnIndex,
    profilePictureBase64: "string",
    tweetContent: "string",
    tweetLike: "string",
    commentorUserName: "string",
    commentorUserId: "hhh",
    commentorContent: "string",
    commentorProfilePictureBase64: "string"

  })










  const [sata, setSata] = useState([])
  const [qnIndex, setQnIndex] = useState(1)
  const { context, setContext } = useStateContext()
  const navigate = useNavigate()

  useEffect(() => {
    setContext({
      timeTaken: 0,
      selectedOptions: []
    })
    createAPIEndpoint(ENDPOINTS.postcomments)
      .fetchById(context.userId)
      .then(res => {
        setSata(res.data)


      })
      .catch(err => { console.log(err); })



  }, [])





  const deletetw = e => {

    createAPIEndpoint(ENDPOINTS.postcomments)
      .delete(qnIndex)
      .then(
          console.log(values)

      )
      .catch(err => console.log(err))
  }


  const {
    values,
  } = useForm(getFreshModel);

  const handleClick = value => () => setQnIndex(value)

  const handleClick1 = value => () => navigate("/Updatetweet", { state: { id: 1, name: value } })











  return (

    sata.length !== 0
      ?
      <Center>


        <Card sx={{ width: 800 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <Typography variant="h3" sx={{ my: 3 }}>
              Ash Tweet
            </Typography>




            <Typography component="h1" variant="h5">
              {'Hello ' + context.userName + '! Whats on your Mind ?'}
            </Typography>

            <ButtonGroup variant="contained" aria-label="outlined primary button group">
              <Button onClick={() => {
                window.location.href = "/postNewTweet"
              }}>Post New Tweet</Button>

              <Button onClick={() => {
                window.location.href = "/homepage"
              }}
              >Home Feed</Button>

              <Button onClick={() => {
                window.location.href = "/ViewAllUsers"
              }}

              >View All Users</Button>

              <Button onClick={() => {
                window.location.href = "/ViewMyTweets"
              }}
              >View My Tweets</Button>

              <Button onClick={() => {
                window.location.href = "/ForgetPass"
              }}
              >Password Reset</Button>






            </ButtonGroup>





            <ul >
              {sata.slice(0).reverse().map(d => (<li key={d.tweetId}>


                <Divider variant="inset" />

                <ListItem alignItems="flex-start">
                  <ListItemAvatar>
                  <Avatar sx={{ bgcolor:purple[500] }}>{d.userName[0]}</Avatar>
                  </ListItemAvatar>

                  <Typography
                    sx={{ display: 'inline' }}
                    component="h6"
                    variant="body3"
                    color="text.primary"

                  >


                  </Typography>




                  <ListItemText
                    primary={d.tweetContent}

                    secondary={
                      <React.Fragment>
                        <Typography
                          sx={{ display: 'inline' }}
                          component="span"
                          variant="body1"
                          color="text.primary"
                        >
                          {d.userName}
                        </Typography>


                        <br></br>
                        {dateFormat(d.id.creationTime, "dddd, mmmm dS, yyyy,HH:mm")}
                        <br></br>

                        {d.commentorContent !== null ? d.commentorContent : null}

                        {d.commentorUserName !== null ? " - " + d.commentorUserName : null}
                        <br></br>

                        <form noValidate autoComplete="off" await onSubmit={deletetw}>

                          <Button
                            type="submit"
                            variant="contained"
                            size="small"

                            id={d.tweetId}
                            onClick={
                              handleClick(d.tweetId)
                            }

                            sx={{ width: '50%' }}
                            startIcon={<DeleteIcon />}>Delete</Button>

                          <Button

                            variant="contained"
                            size="small"

                            id={d.tweetId}
                            onClick={
                              handleClick1(d.tweetId
                              )
                            }

                            sx={{ width: '50%' }}>Update Tweet</Button>








                        </form>






                      </React.Fragment>
                    }
                  />
                </ListItem>





              </li>))}

            </ul>





          </CardContent>
        </Card>
      </Center>
      : <Center>


        <Card sx={{ width: 800 }}>
          <CardContent sx={{ textAlign: 'center' }}>
            <Typography variant="h3" sx={{ my: 3 }}>
              Ash Tweet
            </Typography>


            {() => getFreshModel(context.userName)}

            <Typography component="h1" variant="h5">
              {'Hello ' + context.userName + '! No Tweets For You'}
            </Typography>

            <ButtonGroup variant="contained" aria-label="outlined primary button group">
              <Button onClick={() => {
                window.location.href = "/postNewTweet"
              }}>Post New Tweet</Button>

              <Button onClick={() => {
                window.location.href = "/homepage"
              }}
              >Home Feed</Button>

              <Button onClick={() => {
                window.location.href = "/ViewAllUsers"
              }}

              >View All Users</Button>

              <Button onClick={() => {
                window.location.href = "/ViewMyTweets"
              }}
              >View My Tweets</Button>

              <Button onClick={() => {
                window.location.href = "/ForgetPass"
              }}
              >Password Reset</Button>







            </ButtonGroup>











          </CardContent>
        </Card>
      </Center>























  )
}
